return items.map(function(item) {
  /* ---------- 1. Campos de entrada ---------- */
  const termoOriginal = (
    item.json.TermoPesquisa ||
    item.json.termo ||
    item.json.descricao ||
    ''
  ).toString().trim();

  const termo = termoOriginal
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();

  /* ---------- 2. Listas de apoio ---------- */
  const stopwords   = ['de','da','do','a','o','e','para','com','em','as','os','na','no','por','à','das','dos','um','uma','ao','nao','p','q','c','s'];
  const tipos       = ['pincel','rolo','bandeja','extensor','espátula','desempenadeira','lixa','fita','bico','filtro','kit','massa','tinta','verniz','esmalte','spray','selador','removedor','thinner','diluente','resina','silicone'];
  const formatos    = ['angular','reto','redondo','multiuso','mini','midi','maxi'];
  const materiais   = ['cerdas','nylon','poliester','microfibra','espuma','sintetico','madeira','inox','plastico','aluminio','latao'];
  const acabamentos = ['fosco','acetinado','semibrilho','brilho','alto brilho','textura','premium','rende+'];
  const bases       = ['base agua','base solvente','oleo','epoxi','pu'];
  const volumesPadrao = ['1l','3.6l','18l','400ml','500ml','900ml'];
  const cores       = ['branco','preto','cinza','azul','vermelho','verde','amarelo','marrom','neutro','neve','algodao','neblina','palha'];

  /* ---------- 3. Sinônimos ---------- */
  const sinonimosPalavra = {
    'polegadas': 'polegada',
    'polegada' : 'polegada',
    'branca'   : 'branco',
    'vermelha' : 'vermelho',
    'amarela'  : 'amarelo',
    'trincha'  : 'trincha'
  };

  /* ---------- 4. Tokenização ---------- */
  let palavras_chave = termo
    .replace(/[^\w\s/"]/g, '')
    .split(/[\s,;:-]+/)
    .filter((w, i, a) => w.length > 1 && !stopwords.includes(w) && isNaN(Number(w)) && a.indexOf(w) === i)
    .map(p => sinonimosPalavra[p] || p);

  /* ---------- 5. Detecta tipo principal ---------- */
  let tipo_principal = tipos.find(t => termo.includes(t)) || '';
  if (!tipo_principal && termo.includes('trincha')) tipo_principal = 'pincel';

  if (tipo_principal === 'pincel') {
    if (!palavras_chave.includes('pincel'))  palavras_chave.push('pincel');
    if (!palavras_chave.includes('trincha')) palavras_chave.push('trincha');
  }

  const formato   = formatos.find(f => termo.includes(f)) || '';
  const material  = materiais.find(m => termo.includes(m)) || '';

  /* ---------- 6. Dimensões / tamanho ---------- */
  const matchDim = termo.match(/([0-9]+[.,]?[0-9]*)\s*[x×]\s*([0-9]+[.,]?[0-9]*)(?:\s*(cm|mm))?/);
  const dimensao = matchDim ? matchDim[1] + 'x' + matchDim[2] + (matchDim[3] || '') : '';

  const matchPol = termo.match(/([0-9]+(?:[.,][0-9]+)?)\s*(\"|polegadas?)/i);
  const tamanho  = matchPol ? matchPol[1] + '"' : '';

  /* ---------- 7. Volume, cor, acabamento, base: pega do JSON antes ---------- */
  const corJson        = (item.json.Cor || '').toString().trim().toLowerCase();
  const volumeJson     = (item.json.TamanhoVolume || '').toString().trim().toLowerCase();
  const acabamentoJson = (item.json.Acabamento || '').toString().trim().toLowerCase();
  const baseJson       = (item.json.BasePadrão || '').toString().trim().toLowerCase();

  /* fallback detectado no texto */
  const volPad        = volumesPadrao.find(v => termo.includes(v)) || '';
  const matchVol      = termo.match(/([0-9]+(?:[.,][0-9]+)?)\s*(l|ml|litros?|kg|g)\b/i);
  const volumeDetect  = matchVol ? matchVol[1] + ' ' + matchVol[2] : volPad;

  const termoSyn      = termo.replace(/\bbranca\b/g, 'branco')
                             .replace(/\bpreta\b/g , 'preto')
                             .replace(/\bvermelha\b/g, 'vermelho')
                             .replace(/\bamarela\b/g, 'amarelo');
  const corDetect     = cores.find(c => termoSyn.includes(c)) || '';

  const acabamentoDetect = acabamentos.find(a => termo.includes(a)) || '';
  const baseDetect       = bases.find(b => termo.includes(b))   || '';

  const volumeFinal     = volumeJson     || volumeDetect;
  const corFinal        = corJson        || corDetect;
  const acabamentoFinal = acabamentoJson || acabamentoDetect;
  const baseFinal       = baseJson       || baseDetect;

  /* ---------- 8. Extras ---------- */
  const extras = [];
  if (termo.includes('kit')) extras.push('kit');
  if (termo.includes('profissional')) extras.push('profissional');
  if (termo.includes('premium')) extras.push('premium');
  const extras_str = extras.join('|');

  /* ---------- 9. Marca ---------- */
  const marca = (item.json.Marca || item.json.marca || '').toString().trim().toLowerCase();

  /* ---------- 10. Score SQL ---------- */
  let score_palavras_sql = '';
  palavras_chave.forEach(p => {
    const safe = p.replace(/["']/g, '');
    score_palavras_sql += 
      " + (CASE WHEN unaccent(norm_desc) ILIKE CONCAT('%', unaccent('" +
      safe +
      "'), '%') THEN 0.2 ELSE 0 END)";
  });

  if (marca) {
    score_palavras_sql += 
      " + (CASE WHEN unaccent(norm_desc) ILIKE CONCAT('%', unaccent('" +
      marca +
      "'), '%') THEN 0.4 ELSE 0 END)";
  }

  const reforco_media695 = (tipo_principal === 'pincel' && marca === 'tigre');
  if (reforco_media695) {
    score_palavras_sql +=
      " + (CASE WHEN unaccent(norm_desc) ILIKE '%economica%' THEN 0.25 ELSE 0 END)" +
      " + (CASE WHEN unaccent(norm_desc) ILIKE '%media%' THEN 0.25 ELSE 0 END)" +
      " + (CASE WHEN norm_desc ILIKE '%695%' THEN 0.25 ELSE 0 END)";
  }

  /* ---------- 11. Saída ---------- */
  return {
    json: {
      termo: termoOriginal,
      tipo_principal,
      formato,
      material,
      dimensao,
      tamanho,
      volume: volumeFinal,
      acabamento: acabamentoFinal,
      cor: corFinal,
      base: baseFinal,
      extras,
      extras_str,
      marca,
      superficie: (item.json.superficie || '').toString().trim().toLowerCase(),
      score_palavras_sql
    }
  };
});

// Node único: mescla produto + estoque; retorna apenas saldoDisponivel como 'estoque'
// Entrada: $input.all() -> itens mergeados
// Contexto do pedido: $node['Code5'].json

const entrada = $input.all().map(i => i.json || i);

// pega contexto do pedido
const contextoPedido = $node['Code5'] ? $node['Code5'].json : {};

// mapas auxiliares
const estoqueByCodigo = {};
const produtosByCodigo = {};

const norma = v => v === null || v === undefined ? '' : String(v).trim();

// popula mapas
for (const obj of entrada) {
  if (!obj) continue;

  if (Array.isArray(obj.resultados)) {
    for (const r of obj.resultados) {
      const c = norma(r.codigo_produto || r.codigoProduto || r.codigo);
      if (!c) continue;
      produtosByCodigo[c] = produtosByCodigo[c] || r;
    }
    continue;
  }

  if (obj.codigoProduto !== undefined && obj.saldoDisponivel !== undefined) {
    const c = norma(obj.codigoProduto);
    estoqueByCodigo[c] = obj;
    continue;
  }

  const codigoProdutoKey = obj.codigo_produto || obj.codigoProduto || obj.codigo;
  if (codigoProdutoKey) {
    const c = norma(codigoProdutoKey);
    produtosByCodigo[c] = produtosByCodigo[c] || obj;
    continue;
  }

  if (obj.preco !== undefined || obj.descricao !== undefined) {
    const c = norma(obj.codigo_produto || obj.codigoProduto || obj.codigo);
    if (c) produtosByCodigo[c] = produtosByCodigo[c] || obj;
  }
}

// combinar e devolver só estoqueDisponivel
const resultados = [];

for (const codigo of Object.keys(produtosByCodigo)) {
  const produto = produtosByCodigo[codigo];
  let estoque = estoqueByCodigo[codigo];

  if (!estoque) {
    const alt = estoqueByCodigo[String(Number(codigo))];
    if (alt) estoque = alt;
  }

  if (!estoque) continue;

  const saldo = Number(estoque.saldoDisponivel || 0);
  if (saldo <= 0) continue;

  resultados.push({
    codigo_produto: norma(produto.codigo_produto || produto.codigoProduto || produto.codigo || codigo),
    descricao: produto.descricao || produto.nome || null,
    marca: produto.marca || null,
    preco: produto.preco ?? null,
    score_total: produto.score_total ?? null,
    estoque: saldo   // <<<<< SOMENTE O NÚMERO
  });
}

// saída final
return [
  {
    json: {
      contexto: contextoPedido,
      resultados
    }
  }
];
